package com.agmsolutions.fabrick_test.service;import com.agmsolutions.fabrick_test.Model.dto.*;import com.agmsolutions.fabrick_test.configurations.FabrickApiRest;import com.agmsolutions.fabrick_test.configurations.Response;import com.agmsolutions.fabrick_test.configurations.ResponseList;import org.junit.jupiter.api.DisplayName;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import org.springframework.core.ParameterizedTypeReference;import org.springframework.http.HttpStatus;import org.springframework.web.client.HttpClientErrorException;import org.springframework.web.client.ResourceAccessException;import org.springframework.web.client.RestClient;import java.time.LocalDate;import java.util.ArrayList;import java.util.List;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.ArgumentMatchers.any;import static org.mockito.ArgumentMatchers.anyString;import static org.mockito.Mockito.*;@ExtendWith(MockitoExtension.class)public class AccountServiceTest {    @Mock    private FabrickApiRest fabrickApiRest;    @Mock    private RestClient restClient;    @Mock    private RestClient.RequestHeadersUriSpec uriSpec;    @Mock    private RestClient.ResponseSpec responseSpec;    @Mock    private RestClient.RequestBodyUriSpec bodyUriSpec;    @Mock    private RestClient.RequestBodySpec bodySpec;    @InjectMocks    private AccountService accountService;        @Test    @DisplayName("Test getBalance - success")    void getBalance_success() {        BalanceDto balanceDto = mock(BalanceDto.class);        Response<BalanceDto> response = new Response<>();        response.setPayload(balanceDto);        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.get()).thenReturn(uriSpec);        when(uriSpec.uri(anyString(), any(Object.class))).thenReturn(uriSpec);        when(uriSpec.retrieve()).thenReturn(responseSpec);        when(responseSpec.body(any(ParameterizedTypeReference.class))).thenReturn(response);        BalanceDto result = accountService.getBalance(14537780L);        verify(fabrickApiRest, times(1)).getRestClient();        verify(restClient, times(1)).get();        assertNotNull(result);        assertEquals(balanceDto, result);    }    @Test    @DisplayName("Test getBalance - response null")    void getBalance_responseNull() {        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.get()).thenReturn(uriSpec);        when(uriSpec.uri(anyString(), any(Object.class))).thenReturn(uriSpec);        when(uriSpec.retrieve()).thenReturn(responseSpec);                when(responseSpec.body(any(ParameterizedTypeReference.class))).thenReturn(null);        assertThrows(ResourceAccessException.class, () -> accountService.getBalance(14537780L));    }    @Test    @DisplayName("Test getBalance - response.payload null")    void getBalance_payloadNull() {        Response<BalanceDto> response = new Response<>();        response.setPayload(null);        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.get()).thenReturn(uriSpec);        when(uriSpec.uri(anyString(), any(Object.class))).thenReturn(uriSpec);        when(uriSpec.retrieve()).thenReturn(responseSpec);                when(responseSpec.body(any(ParameterizedTypeReference.class))).thenReturn(response);        assertThrows(ResourceAccessException.class, () -> accountService.getBalance(14537780L));    }    @Test    @DisplayName("Test getBalance - HTTP error")    void getBalance_httpError() {        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.get()).thenReturn(uriSpec);        when(uriSpec.uri(anyString(), any(Object.class))).thenReturn(uriSpec);        when(uriSpec.retrieve()).thenReturn(responseSpec);                when(responseSpec.body(any(ParameterizedTypeReference.class))).thenThrow(new HttpClientErrorException(HttpStatus.BAD_REQUEST));        assertThrows(HttpClientErrorException.class, () -> accountService.getBalance(14537780L));    }    @Test    @DisplayName("Test getTransactions - success")    void getTransactions_success() {        List<TransactionDto> transactions = new ArrayList<>();        transactions.add(mock(TransactionDto.class));                ResponseList<TransactionDto> responseList = new ResponseList<>();        responseList.setList(transactions);        Response<ResponseList<TransactionDto>> response = new Response<>();        response.setPayload(responseList);        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.get()).thenReturn(uriSpec);        when(uriSpec.uri(anyString(), any(), any(), any())).thenReturn(uriSpec);        when(uriSpec.retrieve()).thenReturn(responseSpec);        when(responseSpec.body(any(ParameterizedTypeReference.class))).thenReturn(response);        List<TransactionDto> result = accountService.getTransactions(14537780L, LocalDate.now(), LocalDate.now());        verify(fabrickApiRest, times(1)).getRestClient();        verify(restClient, times(1)).get();        assertNotNull(result);        assertEquals(transactions, result);    }    @Test    @DisplayName("Test getTransactions - response null")    void getTransactions_responseNull() {        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.get()).thenReturn(uriSpec);        when(uriSpec.uri(anyString(), any(), any(), any())).thenReturn(uriSpec);        when(uriSpec.retrieve()).thenReturn(responseSpec);                when(responseSpec.body(any(ParameterizedTypeReference.class))).thenReturn(null);        assertThrows(ResourceAccessException.class, () -> accountService.getTransactions(14537780L, LocalDate.now(), LocalDate.now()));    }    @Test    @DisplayName("Test getTransactions - payload null")    void getTransactions_payloadNull() {        Response<ResponseList<TransactionDto>> response = new Response<>();        response.setPayload(null);        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.get()).thenReturn(uriSpec);        when(uriSpec.uri(anyString(), any(), any(), any())).thenReturn(uriSpec);        when(uriSpec.retrieve()).thenReturn(responseSpec);        when(responseSpec.body(any(ParameterizedTypeReference.class))).thenReturn(response);        assertThrows(ResourceAccessException.class, () -> accountService.getTransactions(14537780L, LocalDate.now(), LocalDate.now()));    }    @Test    @DisplayName("Test getTransactions - empty response list")    void getTransactions_emptyList() {        ResponseList<TransactionDto> responseList = new ResponseList<>();        responseList.setList(new ArrayList<>());        Response<ResponseList<TransactionDto>> response = new Response<>();        response.setPayload(responseList);        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.get()).thenReturn(uriSpec);        when(uriSpec.uri(anyString(), any(), any(), any())).thenReturn(uriSpec);        when(uriSpec.retrieve()).thenReturn(responseSpec);        when(responseSpec.body(any(ParameterizedTypeReference.class))).thenReturn(response);        List<TransactionDto> result = accountService.getTransactions(14537780L, LocalDate.now(), LocalDate.now());        assertNotNull(result);        assertTrue(result.isEmpty());    }    @Test    @DisplayName("Test getTransactions - HTTP error")    void getTransactions_httpError() {        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.get()).thenReturn(uriSpec);        when(uriSpec.uri(anyString(), any(), any(), any())).thenReturn(uriSpec);        when(uriSpec.retrieve()).thenReturn(responseSpec);        when(responseSpec.body(any(ParameterizedTypeReference.class))).thenThrow(new HttpClientErrorException(HttpStatus.BAD_REQUEST));        assertThrows(HttpClientErrorException.class, () -> accountService.getTransactions(14537780L, LocalDate.now(), LocalDate.now()));    }    @Test    @DisplayName("Test createMoneyTransfer - success")    void createMoneyTransfer_success() {        MoneyTransferBodyDto body = mock(MoneyTransferBodyDto.class);        MoneyTransferResponseDto moneyTransferResponseDto = mock(MoneyTransferResponseDto.class);        Response<MoneyTransferResponseDto> response = new Response<>();        response.setPayload(moneyTransferResponseDto);        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.post()).thenReturn(bodyUriSpec);        when(bodyUriSpec.uri(anyString(), any(Object.class))).thenReturn(bodySpec);        when(bodySpec.body(any(Object.class))).thenReturn(bodySpec);        when(bodySpec.retrieve()).thenReturn(responseSpec);        when(responseSpec.body(any(ParameterizedTypeReference.class))).thenReturn(response);        MoneyTransferResponseDto result = accountService.createMoneyTransfer(14537780L, body);        verify(fabrickApiRest, times(1)).getRestClient();        verify(restClient, times(1)).post();        assertNotNull(result);        assertEquals(moneyTransferResponseDto, result);    }    @Test    @DisplayName("Test createMoneyTransfer - response null")    void createMoneyTransfer_responseNull() {        MoneyTransferBodyDto body = mock(MoneyTransferBodyDto.class);        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.post()).thenReturn(bodyUriSpec);        when(bodyUriSpec.uri(anyString(), any(Object.class))).thenReturn(bodySpec);        when(bodySpec.body(any(Object.class))).thenReturn(bodySpec);        when(bodySpec.retrieve()).thenReturn(responseSpec);        when(responseSpec.body(any(ParameterizedTypeReference.class))).thenReturn(null);        assertThrows(ResourceAccessException.class, () -> accountService.createMoneyTransfer(14537780L, body));    }    @Test    @DisplayName("Test createMoneyTransfer - payload null")    void createMoneyTransfer_payloadNull() {        MoneyTransferBodyDto body = mock(MoneyTransferBodyDto.class);        Response<MoneyTransferResponseDto> response = new Response<>();        response.setPayload(null);        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.post()).thenReturn(bodyUriSpec);        when(bodyUriSpec.uri(anyString(), any(Object.class))).thenReturn(bodySpec);        when(bodySpec.body(any(Object.class))).thenReturn(bodySpec);        when(bodySpec.retrieve()).thenReturn(responseSpec);                when(responseSpec.body(any(ParameterizedTypeReference.class))).thenReturn(response);        assertThrows(ResourceAccessException.class, () -> accountService.createMoneyTransfer(14537780L, body));    }    @Test    @DisplayName("Test createMoneyTransfer - HTTP error")    void createMoneyTransfer_httpError() {        MoneyTransferBodyDto body = mock(MoneyTransferBodyDto.class);        when(fabrickApiRest.getRestClient()).thenReturn(restClient);        when(restClient.post()).thenReturn(bodyUriSpec);        when(bodyUriSpec.uri(anyString(), any(Object.class))).thenReturn(bodySpec);        when(bodySpec.body(any(Object.class))).thenReturn(bodySpec);        when(bodySpec.retrieve()).thenReturn(responseSpec);        when(responseSpec.body(any(ParameterizedTypeReference.class))).thenThrow(new HttpClientErrorException(HttpStatus.BAD_REQUEST));        assertThrows(HttpClientErrorException.class, () -> accountService.createMoneyTransfer(14537780L, body));    }}